@namespace Lumeo

@{
    var context = new PopoverContext(EffectiveOpen, EventCallback.Factory.Create<bool>(this, SetOpen), _wrapperId, _contentId);
}

<CascadingValue Value="context" IsFixed="false">
    @* tabindex=-1 makes the wrapper a programmatic focus target so PopoverContent
       can return focus here on close (the trigger lives inside it). *@
    <div id="@_wrapperId" class="@Cx.Merge("relative inline-block outline-none", Class)" tabindex="-1" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    /// <summary>
    /// Extra CSS classes for the popover ROOT wrapper div, e.g. <c>w-full</c> to
    /// un-shrink-wrap a full-width trigger contained inside. The base classes
    /// (<c>relative inline-block outline-none</c>) are always preserved.
    /// </summary>
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("popover");
    // Stable content id shared with the trigger (aria-controls) and the content
    // (focus management / role=dialog target) so the trigger can advertise the
    // relationship and the content can focus itself on open.
    internal readonly string _contentId = LumeoIds.New("popover-content");

    // battle-wave2 #183 (state-on-data-change) — uncontrolled open state lives in
    // a private backing field, NOT in the [Parameter] Open. Blazor re-applies
    // [Parameter] values from the parent on every render, so self-managing state
    // by writing back into Open got silently reset whenever an unrelated parent
    // re-render pushed the original Open value down (precedent #3 / Collapsible #246).
    private bool _openState;
    private bool _initialized;
    private bool _lastOpenParam;

    /// <summary>
    /// State the component actually renders from. Controlled (OpenChanged bound):
    /// the parent owns it, so mirror Open verbatim. Uncontrolled: use our own
    /// backing field so parent re-renders can't clobber it.
    /// </summary>
    private bool EffectiveOpen => OpenChanged.HasDelegate ? Open : _openState;

    protected override void OnParametersSet()
    {
        // Seed the uncontrolled backing field from Open on first set (honours an
        // initial Open="true") and whenever the bound Open value actually changes
        // (lets callers still drive it imperatively), but never on the no-op
        // re-applications that caused the reset.
        if (!_initialized || Open != _lastOpenParam)
        {
            _openState = Open;
            _lastOpenParam = Open;
            _initialized = true;
        }
    }

    private async Task SetOpen(bool value)
    {
        // Controlled (Open is bound via OpenChanged): let the parent own state —
        // fire the callback and render from the parent's next value instead of
        // mutating our own [Parameter], which desyncs if the parent rejects or
        // ignores the change. Uncontrolled: self-manage via the backing field.
        if (OpenChanged.HasDelegate)
        {
            await OpenChanged.InvokeAsync(value);
        }
        else
        {
            _openState = value;
        }
    }

    public record PopoverContext(bool IsOpen, EventCallback<bool> SetOpen, string WrapperId, string ContentId);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.IsOpen)
{
    <div id="@_contentId" role="dialog" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public Popover.PopoverContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Align Align { get; set; } = Lumeo.Align.Center;
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Bottom;
    [Parameter] public bool ShowArrow { get; set; }
    /// <summary>
    /// When <c>true</c> (default), focus moves into the popover surface on open so its
    /// <c>@onkeydown</c> handler receives Escape and keyboard users land inside the dialog
    /// (the Radix <c>onOpenAutoFocus</c> default). Set to <c>false</c> when the trigger is a
    /// typeable control that must KEEP focus while the popover opens (e.g. DatePicker's
    /// keyboard-input trigger) — the surface still positions, registers click-outside and
    /// saves/restores focus, it just doesn't steal focus from the trigger on open.
    /// </summary>
    [Parameter] public bool FocusOnOpen { get; set; } = true;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Use the content id provided by the Popover parent so the trigger's
    // aria-controls points at this element and focus management can target it.
    private string _contentId => Context.ContentId;
    private bool _registered;
    // battle-wave2 #86 (state-on-data-change) — remember the anchor (Side/Align)
    // we last positioned against. The `_registered` latch guards the one-shot
    // click-outside registration + focus-on-open, but it also blocked any
    // re-position, so a Side/Align change while the popover stayed OPEN was
    // silently ignored and the surface stuck to its first-open placement.
    private (string Side, string Align)? _appliedAnchor;

    private string CssClass => Cx.Merge(
        "fixed z-50 w-72 rounded-md border border-border/60 bg-popover p-4 text-popover-foreground shadow-lg outline-none",
        ShowArrow ? "overflow-visible" : "overflow-hidden",
        "animate-fade-in",
        Class);

    private string AlignStr => Align switch
    {
        Lumeo.Align.Start => "start",
        Lumeo.Align.Center => "center",
        Lumeo.Align.End => "end",
        _ => "center"
    };

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "bottom"
    };

    // Rotated square so the arrow inherits both the popover surface colour AND a matching border
    // on the two sides that face out — looks sharper than the hollow-triangle trick and lines the
    // arrow up with the popover corner radius visually.
    private string ArrowClasses => Side switch
    {
        Lumeo.Side.Top => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-r border-border/60",
        Lumeo.Side.Bottom => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60",
        Lumeo.Side.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-r border-border/60",
        Lumeo.Side.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-l border-border/60",
        _ => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(_contentId, Context.WrapperId, AlignStr, false, SideStr);
            _appliedAnchor = (SideStr, AlignStr);
            await Interop.RegisterClickOutside(_contentId, Context.WrapperId, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;

            // Stash the element that had focus when we opened (the trigger), keyed
            // by the content id, BEFORE moving focus inward. On close RestoreFocus
            // hands focus back to it — the WCAG 2.4.3 contract — but only when that
            // element is still in the document. battle-wave2 #87 (keyboard-a11y):
            // the old close path unconditionally focused the wrapper, so a
            // programmatic/external close stole focus back to the trigger even when
            // the user had already moved focus elsewhere. SaveFocus/RestoreFocus is
            // the same non-modal idiom Select/DropdownMenu/ContextMenu use; it
            // no-ops when the saved element is gone instead of yanking focus.
            try { await Interop.SaveFocus(_contentId); } catch (JSDisconnectedException) { }

            // Move focus into the dialog content on open. Without this, focus
            // stays on the trigger and the content's @onkeydown handler never
            // receives Escape (Radix-equivalent dialog popovers manage focus).
            // Skipped when FocusOnOpen is false so a typeable trigger (DatePicker's
            // keyboard input) keeps focus and stays typeable while the popover opens.
            if (FocusOnOpen)
            {
                try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
            }
        }
        else if (Context.IsOpen && _registered && _appliedAnchor != (SideStr, AlignStr))
        {
            // #86 — Side/Align changed while the popover stayed open: re-run
            // PositionFixed against the new anchor. The tuple compare keeps a
            // same-anchor re-render from churning the floating-ui placement.
            await Interop.PositionFixed(_contentId, Context.WrapperId, AlignStr, false, SideStr);
            _appliedAnchor = (SideStr, AlignStr);
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape") await Context.SetOpen.InvokeAsync(false);
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        // Return focus to whatever had it when we opened (the trigger), so keyboard
        // users aren't dropped back to the document body. battle-wave2 #87
        // (keyboard-a11y): use RestoreFocus instead of an unconditional
        // FocusElement(WrapperId) — RestoreFocus only re-focuses the saved element
        // when it is still connected, so a programmatic/external close while the
        // user's focus is elsewhere no longer steals it back to the trigger.
        try { await Interop.RestoreFocus(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
        // Clear the applied anchor so the next open re-positions from scratch.
        _appliedAnchor = null;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@if (AsChild)
{
    @* asChild: render NO wrapper. Cascade the slot so a cooperating child (a Lumeo
       <Button>, or a manual <ChildContentSlot> splat) becomes the single trigger
       element — no role=button div, no nested-interactive markup, and the child's
       own Class/width reach the real control. Popover positions against the Popover
       ROOT wrapper (Context.WrapperId), not this trigger, so dropping the wrapper
       does not affect positioning — no id transfer needed. *@
    <CascadingValue Value="Slot" IsFixed="false">
        @if (ChildContentSlot is not null)
        {
            @ChildContentSlot(Slot)
        }
        else
        {
            @ChildContent
        }
    </CascadingValue>
}
else
{
    <div id="@EffectiveTriggerId" class="@CssClass" role="button" tabindex="0" aria-expanded="@(Context.IsOpen ? "true" : "false")" aria-haspopup="dialog" aria-controls="@(Context.IsOpen ? Context.ContentId : null)" @onclick="Toggle" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public Popover.PopoverContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Tier-2 escape hatch for <see cref="AsChild"/> with arbitrary (non-Lumeo) markup:
    /// receives the <see cref="TriggerSlot"/> so the consumer can splat
    /// <c>@attributes="slot.Attributes"</c> and wire <c>@onclick="slot.OnClick.InvokeAsync"</c>
    /// onto their own single element. Lumeo <c>&lt;Button&gt;</c> children need only
    /// <see cref="AsChild"/> — they consume the slot automatically.
    /// </summary>
    [Parameter] public RenderFragment<TriggerSlot>? ChildContentSlot { get; set; }

    /// <summary>
    /// When <c>true</c>, the trigger renders NO wrapper element and instead cascades a
    /// <see cref="TriggerSlot"/> that a cooperating child folds onto its own single root
    /// element — yielding ONE DOM node with merged class, composed click/keyboard, and
    /// forwarded ARIA/state (the Radix <c>asChild</c> goal). The child must resolve to
    /// exactly one cooperating element (a Lumeo <c>&lt;Button&gt;</c>, or a manual
    /// <see cref="ChildContentSlot"/> splat); raw HTML/3rd-party markup receives nothing.
    /// Default <c>false</c> preserves the current <c>role=button</c> wrapper exactly.
    ///
    /// Prefer a <c>&lt;button&gt;</c> child for a click-toggle trigger: a
    /// <c>&lt;Button Href&gt;</c> renders an <c>&lt;a&gt;</c>, which natively activates
    /// on Enter only (not Space), so Space would not open the popover.
    /// </summary>
    [Parameter] public bool AsChild { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable FALLBACK id for the role=button trigger. AsChild renders no wrapper, so
    // this id is only emitted/registered on the non-AsChild branch below.
    private readonly string _triggerId = LumeoIds.New("popover-trigger");
    // The id that ACTUALLY renders on the <div>: a consumer-splatted id in AdditionalAttributes
    // wins (it renders after the explicit id= in the markup above), else the fallback. The Space-
    // default suppression (battle-wave2 #88) must register against THIS, not the raw _triggerId —
    // otherwise a consumer-supplied id leaves the suppression targeting an id no element carries,
    // so Space silently scrolls the page again while toggling the popover (Codex P3). Mirrors
    // DialogTrigger/SheetTrigger's _id.
    private string EffectiveTriggerId => LumeoIds.Effective(AdditionalAttributes, _triggerId);
    private bool _pdRegistered;

    private string CssClass => Cx.Merge("inline-flex", Class);

    private TriggerSlot Slot => new(
        Id: null,                                 // Popover anchors positioning on its root wrapper, not the trigger
        Class: Cx.Merge("inline-flex", Class),
        Attributes: BuildAttrs(),
        OnClick: EventCallback.Factory.Create<MouseEventArgs>(this, _ => Toggle()),
        OnKeyDown: EventCallback.Factory.Create<KeyboardEventArgs>(this, HandleKeyDown));

    private IReadOnlyDictionary<string, object> BuildAttrs()
    {
        var d = new Dictionary<string, object>
        {
            ["aria-haspopup"] = "dialog",
            ["aria-expanded"] = Context.IsOpen ? "true" : "false",
        };
        if (Context.IsOpen) d["aria-controls"] = Context.ContentId;
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
        return d;
    }

    private async Task Toggle() => await Context.SetOpen.InvokeAsync(!Context.IsOpen);

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Toggle();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || AsChild) return;
        try
        {
            // battle-wave2 #88 (keyboard-a11y): the fallback div[role=button] has no
            // native key synthesis, so Space both opened the popover AND scrolled the
            // page. Suppress only Space's default synchronously in JS (Enter has no
            // default on a div). Calling e.PreventDefault from the async @onkeydown
            // handler is too late — the default has already fired — and
            // @onkeydown:preventDefault would also trap Tab; the JS-side key-selective
            // rule is the library idiom (Collapsible/Accordion/Tabs triggers).
            await Interop.RegisterPreventDefaultKeys(
                EffectiveTriggerId,
                new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(EffectiveTriggerId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
